// Transform Apify response to Instagram native format for downstream compatibility
const response = $json || {};

// Error handling
if (!response.success || !response.data) {
  return [{
    json: {
      error: response.error || 'Failed to scrape Instagram profile',
      errorCode: response.errorCode || 'scraping_failed'
    }
  }];
}

const profile = response.data;

// Transform Apify format to Instagram native format
// This ensures compatibility with downstream nodes expecting Instagram native structure
const transformedData = {
  success: true,
  data: {
    user: {
      username: profile.username || '',
      full_name: profile.fullName || '',
      biography: profile.biography || '',
      edge_followed_by: {
        count: profile.followerCount || 0
      },
      edge_follow: {
        count: profile.followingCount || 0
      },
      profile_pic_url: profile.profilePicUrl || '',
      is_verified: profile.isVerified || false,
      is_business_account: profile.isBusinessAccount || false
    },
    edge_owner_to_timeline_media: {
      edges: (profile.posts || []).map(post => ({
        node: {
          id: post.id || '',
          caption: post.caption || '',
          timestamp: post.timestamp || new Date().toISOString(),
          edge_media_to_caption: {
            edges: post.caption ? [
              {
                node: {
                  text: post.caption
                }
              }
            ] : []
          },
          edge_media_preview_like: {
            count: post.likeCount || 0
          },
          edge_media_to_comment: {
            count: post.commentCount || 0
          },
          is_carousel: post.isCarousel || false
        }
      }))
    }
  }
};

return [{ json: transformedData }];

// Parse webhook dari Next.js
const body = $json.body || $json;
return [{
  json: {
    request_id: body.request_id,
    callback_token: body.callback_token,
    platform: body.platform,
    profile_url: body.profile_url,
    notes: body.notes,
    progress_callback_url: body.progress_callback_url,
    result_callback_url: body.result_callback_url,
    error_callback_url: body.error_callback_url,
    timestamp: new Date().toISOString()
  }
}];

// Check quota available - one-time purchase model

const entitlement = $json || {};

const quota_used = Number(entitlement.quota_used || 0);
const quota_total = Number(entitlement.quota_total || 0);

const quota_available =
  entitlement.status === 'active' &&
  quota_used < quota_total;

// Parse Webhook Data sudah object
const webhookData =
  $('Parse Webhook Data1').first()?.json || {};

return [
  {
    json: {
      ...webhookData,

      entitlement,

      quota_available,

      quota_remaining: Math.max(
        0,
        quota_total - quota_used
      )
    }
  }
];

// Validate Instagram URL format
const profile_url = $json.profile_url || "";
const ig_regex = /https:\/\/(www\.)?instagram\.com\/([a-zA-Z0-9_\.]+)\/?/;
const match = profile_url.match(ig_regex);

if (!match || !match[2]) {
  return [{
    json: { 
      valid: false, 
      error: "Format Instagram URL tidak valid. Gunakan: https://instagram.com/username"
    }
  }];
}

return [{
  json: {
    ...Object.assign({}, $json),
    valid: true,
    ig_username: match[2],
    ig_profile_url: `https://instagram.com/${match[2]}`
  }
}];

// Extract IG data and prepare for AI analysis
const webhookData = $('Parse Webhook Data1').first()?.json || {};
const scrapedData = $('Transform Instagram Data').first()?.json || {};
const ig_data = scrapedData.data || scrapedData.raw_ig_data || scrapedData;
const user = ig_data.user || {};
const posts = ig_data.edge_owner_to_timeline_media?.edges || [];
const profileUrl = webhookData.profile_url || '';
const usernameMatch = profileUrl.match(/instagram\.com\/([a-zA-Z0-9_\.]+)/);
const ig_username = usernameMatch?.[1] || webhookData.ig_username || 'unknown';

const captions = posts
  .slice(0, 10)
  .map(p => p.node?.edge_media_to_caption?.edges?.[0]?.node?.text || '')
  .filter(c => c.length > 0);

const prompt = `
Analyze Instagram account data and provide:
1. Sentiment Analysis: Positive/Neutral/Negative breakdown (%) from captions
2. Engagement Analysis: Average likes, comments, shares per post
3. Top Topics: Main themes in captions
4. Audience Insights: Follower demographics if available
5. Recommendations: 3-5 actionable tips to improve engagement

Account: @${ig_username}
Followers: ${user.edge_followed_by?.count || 0}
Following: ${user.edge_follow?.count || 0}
Bio: ${user.biography || ''}

Recent captions:
${captions.join('\n\n')}

Provide JSON response:
{
  "sentiment_label": "positive|neutral|negative",
  "sentiment_score": 0-1,
  "engagement_score": 0-100,
  "top_topics": ["topic1", "topic2"],
  "audience_insight": {"demographics": "..."},
  "recommendations": ["rec1", "rec2", "rec3"]
}`;

return [{
  json: {
    ...webhookData,
    ai_prompt: prompt,
    raw_ig_data: ig_data,
    ig_username,
    profile_url: webhookData.profile_url || profileUrl
  }
}];
